-- Tencent-04 phase 1 CloudBase MySQL schema draft.
-- Target stack: EdgeOne Pages + CloudBase HTTP Functions + CloudBase Auth v2 + CloudBase MySQL.
--
-- Notes:
-- - This file is intentionally independent from supabase/migrations.
-- - IDs are varchar(36) and should be generated by CloudBase HTTP Functions
--   with UUID/ULID logic. This avoids PostgreSQL uuid/gen_random_uuid syntax.
-- - Private tables include id, _openid, user_id, created_at and updated_at.
-- - _openid is the CloudBase identity key. user_id is the application-level
--   filtering key. In the first phase they can keep the same value.
-- - MySQL JSON columns do not use JSONB or PostgreSQL casts.
-- - RLS is replaced by service-layer WHERE _openid = ? AND user_id = ? filters.
-- - Quota RPC is replaced later by MySQL transactions with row locks.

CREATE TABLE IF NOT EXISTS app_profiles (
  id VARCHAR(36) NOT NULL,
  _openid VARCHAR(128) NOT NULL,
  user_id VARCHAR(128) NOT NULL,
  email VARCHAR(320) NULL,
  display_name VARCHAR(255) NULL,
  role ENUM('demo_user', 'admin') NOT NULL DEFAULT 'demo_user',
  status ENUM('active', 'disabled') NOT NULL DEFAULT 'active',
  metadata JSON NOT NULL,
  created_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  updated_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3),
  PRIMARY KEY (id),
  UNIQUE KEY uk_app_profiles_openid (_openid),
  UNIQUE KEY uk_app_profiles_user_id (user_id),
  KEY idx_app_profiles_created_at (created_at)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS agent_run_quota (
  id VARCHAR(36) NOT NULL,
  _openid VARCHAR(128) NOT NULL,
  user_id VARCHAR(128) NOT NULL,
  quota_type ENUM('agent_run') NOT NULL DEFAULT 'agent_run',
  quota_limit INT UNSIGNED NOT NULL DEFAULT 20,
  quota_used INT UNSIGNED NOT NULL DEFAULT 0,
  period_start DATETIME(3) NOT NULL,
  period_end DATETIME(3) NULL,
  metadata JSON NOT NULL,
  created_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  updated_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3),
  PRIMARY KEY (id),
  UNIQUE KEY uk_agent_run_quota_user_period (user_id, quota_type, period_start),
  KEY idx_agent_run_quota_openid (_openid),
  KEY idx_agent_run_quota_user_id (user_id),
  KEY idx_agent_run_quota_created_at (created_at),
  CONSTRAINT fk_agent_run_quota_profile_user
    FOREIGN KEY (user_id) REFERENCES app_profiles (user_id)
    ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS agent_run_usage (
  id VARCHAR(36) NOT NULL,
  _openid VARCHAR(128) NOT NULL,
  user_id VARCHAR(128) NOT NULL,
  run_id VARCHAR(128) NULL,
  quota_type ENUM('agent_run') NOT NULL DEFAULT 'agent_run',
  status ENUM('started', 'completed', 'failed', 'stopped') NOT NULL,
  started_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  finished_at DATETIME(3) NULL,
  error_code VARCHAR(128) NULL,
  metadata JSON NOT NULL,
  created_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  updated_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3),
  PRIMARY KEY (id),
  KEY idx_agent_run_usage_openid (_openid),
  KEY idx_agent_run_usage_user_id (user_id),
  KEY idx_agent_run_usage_run_id (run_id),
  KEY idx_agent_run_usage_created_at (created_at),
  KEY idx_agent_run_usage_user_started (user_id, started_at),
  CONSTRAINT fk_agent_run_usage_profile_user
    FOREIGN KEY (user_id) REFERENCES app_profiles (user_id)
    ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS conversations (
  id VARCHAR(36) NOT NULL,
  _openid VARCHAR(128) NOT NULL,
  user_id VARCHAR(128) NOT NULL,
  title VARCHAR(255) NOT NULL DEFAULT '新会话',
  summary TEXT NULL,
  mode ENUM('mock', 'agent', 'mixed') NOT NULL DEFAULT 'mock',
  status ENUM('active', 'running', 'completed', 'failed', 'archived') NOT NULL DEFAULT 'active',
  visibility ENUM('private', 'demo', 'system') NOT NULL DEFAULT 'private',
  source_template_id VARCHAR(36) NULL,
  latest_run_id VARCHAR(36) NULL,
  message_count INT UNSIGNED NOT NULL DEFAULT 0,
  archived_at DATETIME(3) NULL,
  metadata JSON NOT NULL,
  created_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  updated_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3),
  PRIMARY KEY (id),
  KEY idx_conversations_openid (_openid),
  KEY idx_conversations_user_id (user_id),
  KEY idx_conversations_created_at (created_at),
  KEY idx_conversations_user_updated (user_id, updated_at),
  KEY idx_conversations_user_status_updated (user_id, status, updated_at),
  KEY idx_conversations_source_template_id (source_template_id),
  KEY idx_conversations_latest_run_id (latest_run_id),
  CONSTRAINT fk_conversations_profile_user
    FOREIGN KEY (user_id) REFERENCES app_profiles (user_id)
    ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS agent_runs (
  id VARCHAR(36) NOT NULL,
  _openid VARCHAR(128) NOT NULL,
  user_id VARCHAR(128) NOT NULL,
  conversation_id VARCHAR(36) NOT NULL,
  usage_id VARCHAR(36) NULL,
  runtime_run_id VARCHAR(128) NULL,
  mode ENUM('mock', 'agent') NOT NULL DEFAULT 'agent',
  status ENUM('pending', 'running', 'completed', 'failed', 'stopped') NOT NULL DEFAULT 'running',
  intent VARCHAR(64) NULL,
  prompt MEDIUMTEXT NULL,
  plan JSON NOT NULL,
  data_source_snapshot JSON NOT NULL,
  chart_data JSON NOT NULL,
  conclusion MEDIUMTEXT NULL,
  conclusion_source VARCHAR(64) NULL,
  report_state VARCHAR(64) NULL,
  started_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  completed_at DATETIME(3) NULL,
  elapsed_ms INT UNSIGNED NULL,
  error_message TEXT NULL,
  metadata JSON NOT NULL,
  created_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  updated_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3),
  PRIMARY KEY (id),
  KEY idx_agent_runs_openid (_openid),
  KEY idx_agent_runs_user_id (user_id),
  KEY idx_agent_runs_conversation_id (conversation_id),
  KEY idx_agent_runs_usage_id (usage_id),
  KEY idx_agent_runs_runtime_run_id (runtime_run_id),
  KEY idx_agent_runs_created_at (created_at),
  KEY idx_agent_runs_user_started (user_id, started_at),
  KEY idx_agent_runs_conversation_started (conversation_id, started_at),
  CONSTRAINT fk_agent_runs_conversation
    FOREIGN KEY (conversation_id) REFERENCES conversations (id)
    ON DELETE CASCADE,
  CONSTRAINT fk_agent_runs_usage
    FOREIGN KEY (usage_id) REFERENCES agent_run_usage (id)
    ON DELETE SET NULL,
  CONSTRAINT fk_agent_runs_profile_user
    FOREIGN KEY (user_id) REFERENCES app_profiles (user_id)
    ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS messages (
  id VARCHAR(36) NOT NULL,
  _openid VARCHAR(128) NOT NULL,
  user_id VARCHAR(128) NOT NULL,
  conversation_id VARCHAR(36) NOT NULL,
  role ENUM('user', 'assistant', 'system') NOT NULL,
  kind ENUM('text', 'tool_summary', 'report', 'error', 'system_notice') NOT NULL DEFAULT 'text',
  content MEDIUMTEXT NOT NULL,
  run_id VARCHAR(36) NULL,
  client_message_id VARCHAR(128) NULL,
  status ENUM('pending', 'streaming', 'completed', 'failed') NOT NULL DEFAULT 'completed',
  metadata JSON NOT NULL,
  created_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  updated_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3),
  PRIMARY KEY (id),
  UNIQUE KEY uk_messages_user_client_message (user_id, client_message_id),
  KEY idx_messages_openid (_openid),
  KEY idx_messages_user_id (user_id),
  KEY idx_messages_conversation_id (conversation_id),
  KEY idx_messages_run_id (run_id),
  KEY idx_messages_created_at (created_at),
  KEY idx_messages_conversation_created (conversation_id, created_at),
  KEY idx_messages_user_created (user_id, created_at),
  CONSTRAINT fk_messages_conversation
    FOREIGN KEY (conversation_id) REFERENCES conversations (id)
    ON DELETE CASCADE,
  CONSTRAINT fk_messages_run
    FOREIGN KEY (run_id) REFERENCES agent_runs (id)
    ON DELETE SET NULL,
  CONSTRAINT fk_messages_profile_user
    FOREIGN KEY (user_id) REFERENCES app_profiles (user_id)
    ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS run_events (
  id VARCHAR(36) NOT NULL,
  _openid VARCHAR(128) NOT NULL,
  user_id VARCHAR(128) NOT NULL,
  run_id VARCHAR(36) NOT NULL,
  conversation_id VARCHAR(36) NOT NULL,
  seq INT UNSIGNED NOT NULL,
  event_type VARCHAR(64) NOT NULL,
  payload JSON NOT NULL,
  created_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  updated_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3),
  PRIMARY KEY (id),
  UNIQUE KEY uk_run_events_run_seq (run_id, seq),
  KEY idx_run_events_openid (_openid),
  KEY idx_run_events_user_id (user_id),
  KEY idx_run_events_conversation_id (conversation_id),
  KEY idx_run_events_run_id (run_id),
  KEY idx_run_events_created_at (created_at),
  KEY idx_run_events_conversation_created (conversation_id, created_at),
  KEY idx_run_events_user_created (user_id, created_at),
  CONSTRAINT fk_run_events_run
    FOREIGN KEY (run_id) REFERENCES agent_runs (id)
    ON DELETE CASCADE,
  CONSTRAINT fk_run_events_conversation
    FOREIGN KEY (conversation_id) REFERENCES conversations (id)
    ON DELETE CASCADE,
  CONSTRAINT fk_run_events_profile_user
    FOREIGN KEY (user_id) REFERENCES app_profiles (user_id)
    ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS tool_invocations (
  id VARCHAR(36) NOT NULL,
  _openid VARCHAR(128) NOT NULL,
  user_id VARCHAR(128) NOT NULL,
  run_id VARCHAR(36) NOT NULL,
  conversation_id VARCHAR(36) NOT NULL,
  tool_name VARCHAR(128) NOT NULL,
  display_name VARCHAR(255) NOT NULL,
  status ENUM('pending', 'running', 'completed', 'failed', 'skipped') NOT NULL DEFAULT 'running',
  input JSON NOT NULL,
  input_summary TEXT NULL,
  output JSON NOT NULL,
  output_summary TEXT NULL,
  started_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  finished_at DATETIME(3) NULL,
  elapsed_ms INT UNSIGNED NULL,
  error TEXT NULL,
  metadata JSON NOT NULL,
  created_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  updated_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3),
  PRIMARY KEY (id),
  KEY idx_tool_invocations_openid (_openid),
  KEY idx_tool_invocations_user_id (user_id),
  KEY idx_tool_invocations_conversation_id (conversation_id),
  KEY idx_tool_invocations_run_id (run_id),
  KEY idx_tool_invocations_created_at (created_at),
  KEY idx_tool_invocations_user_started (user_id, started_at),
  KEY idx_tool_invocations_user_tool_started (user_id, tool_name, started_at),
  KEY idx_tool_invocations_run_started (run_id, started_at),
  KEY idx_tool_invocations_conversation_started (conversation_id, started_at),
  CONSTRAINT fk_tool_invocations_run
    FOREIGN KEY (run_id) REFERENCES agent_runs (id)
    ON DELETE CASCADE,
  CONSTRAINT fk_tool_invocations_conversation
    FOREIGN KEY (conversation_id) REFERENCES conversations (id)
    ON DELETE CASCADE,
  CONSTRAINT fk_tool_invocations_profile_user
    FOREIGN KEY (user_id) REFERENCES app_profiles (user_id)
    ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS report_artifacts (
  id VARCHAR(36) NOT NULL,
  _openid VARCHAR(128) NOT NULL,
  user_id VARCHAR(128) NOT NULL,
  conversation_id VARCHAR(36) NOT NULL,
  run_id VARCHAR(36) NULL,
  title VARCHAR(255) NOT NULL,
  content_markdown MEDIUMTEXT NOT NULL,
  status ENUM('draft', 'generated', 'archived') NOT NULL DEFAULT 'generated',
  version INT UNSIGNED NOT NULL DEFAULT 1,
  metadata JSON NOT NULL,
  created_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  updated_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3),
  PRIMARY KEY (id),
  KEY idx_report_artifacts_openid (_openid),
  KEY idx_report_artifacts_user_id (user_id),
  KEY idx_report_artifacts_conversation_id (conversation_id),
  KEY idx_report_artifacts_run_id (run_id),
  KEY idx_report_artifacts_created_at (created_at),
  KEY idx_report_artifacts_user_created (user_id, created_at),
  KEY idx_report_artifacts_conversation_created (conversation_id, created_at),
  CONSTRAINT fk_report_artifacts_conversation
    FOREIGN KEY (conversation_id) REFERENCES conversations (id)
    ON DELETE CASCADE,
  CONSTRAINT fk_report_artifacts_run
    FOREIGN KEY (run_id) REFERENCES agent_runs (id)
    ON DELETE SET NULL,
  CONSTRAINT fk_report_artifacts_profile_user
    FOREIGN KEY (user_id) REFERENCES app_profiles (user_id)
    ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS demo_task_templates (
  id VARCHAR(36) NOT NULL,
  title VARCHAR(255) NOT NULL,
  description TEXT NOT NULL,
  prompt TEXT NOT NULL,
  category ENUM('intro', 'analysis', 'report', 'rag', 'long_context', 'fallback') NOT NULL,
  recommended_mode ENUM('mock', 'agent') NOT NULL DEFAULT 'mock',
  sort_order INT NOT NULL DEFAULT 0,
  is_enabled TINYINT(1) NOT NULL DEFAULT 1,
  metadata JSON NOT NULL,
  created_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  updated_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3),
  PRIMARY KEY (id),
  KEY idx_demo_task_templates_enabled_sort (is_enabled, sort_order),
  KEY idx_demo_task_templates_category_sort (category, sort_order),
  KEY idx_demo_task_templates_created_at (created_at)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS demo_conversation_templates (
  id VARCHAR(36) NOT NULL,
  title VARCHAR(255) NOT NULL,
  description TEXT NOT NULL,
  category ENUM('intro', 'analysis', 'report', 'rag', 'long_context', 'fallback') NOT NULL,
  visibility ENUM('demo', 'system') NOT NULL DEFAULT 'demo',
  seed_messages JSON NOT NULL,
  seed_runs JSON NOT NULL,
  seed_reports JSON NOT NULL,
  sort_order INT NOT NULL DEFAULT 0,
  is_enabled TINYINT(1) NOT NULL DEFAULT 1,
  metadata JSON NOT NULL,
  created_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  updated_at DATETIME(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3),
  PRIMARY KEY (id),
  KEY idx_demo_conversation_templates_enabled_sort (is_enabled, sort_order),
  KEY idx_demo_conversation_templates_category_sort (category, sort_order),
  KEY idx_demo_conversation_templates_created_at (created_at)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Future RAG extension, intentionally not created in phase 1:
-- - knowledge_sources
-- - knowledge_documents
-- - knowledge_chunks
-- - rag_retrieval_logs
--
-- RAG phase notes:
-- - Keep _openid and user_id on private RAG rows.
-- - Replace PostgreSQL tsvector/Gin indexes with MySQL FULLTEXT or external
--   vector/search service after retrieval strategy is finalized.
-- - Keep retrieval logs filtered by _openid/user_id in every repository query.

-- Quota transaction replacement notes:
-- Supabase RPC consume_agent_run_quota should become a CloudBase HTTP Function
-- repository operation using a MySQL transaction:
--
-- START TRANSACTION;
-- 1. SELECT role FROM app_profiles WHERE user_id = ? AND _openid = ? FOR UPDATE;
-- 2. INSERT monthly agent_run_quota row if absent.
-- 3. SELECT quota row FOR UPDATE.
-- 4. If role = admin, insert agent_run_usage without incrementing quota.
-- 5. If demo_user and quota_used < quota_limit:
--      UPDATE agent_run_quota SET quota_used = quota_used + 1 WHERE id = ?;
--      INSERT agent_run_usage(status='started', ...);
--    Else rollback or commit without usage and return quota_exceeded.
-- COMMIT;
--
-- finish_agent_run_usage becomes a normal UPDATE scoped by id, _openid and
-- user_id inside the CloudBase function.
